class QState:
    """Represents a superposition of possible states for an agent or a problem.
    Internally, it's a complex-valued tensor.
    """

    def __init__(self, num_dimensions: int = 2, tensor: Optional[torch.Tensor] = None):
        """
        Initialize a QState with a given number of dimensions or a provided tensor.
        """
        if tensor is not None:
            if not isinstance(tensor, torch.Tensor):
                raise TypeError("tensor must be a torch.Tensor")
            self.tensor = tensor
        else:
            # Initialize with a uniform superposition state (Random initialization)
            self.tensor = torch.randn(num_dimensions, dtype=torch.complex64)
            self.normalize()

    def normalize(self) -> None:
        """Ensures the sum of squared magnitudes (probabilities) is 1."""
        norm = torch.sqrt(torch.sum(torch.abs(self.tensor)**2))
        if norm > 0:
            self.tensor /= norm

    def amplitudes(self) -> torch.Tensor:
        """Returns the probability amplitudes."""
        return self.tensor

    def probabilities(self) -> torch.Tensor:
        """Returns the probabilities of each state (magnitudes squared)."""
        return torch.abs(self.tensor)**2

    def resolve(self) -> int:
        """Collapses the superposition state into a single outcome based on probabilities."""
        probs = self.probabilities().detach()
        return torch.multinomial(probs, 1).item()

    def apply_operator(self, operator: 'QOperator') -> 'QState':
        """Apply a quantum-inspired operator to the state."""
        new_tensor = torch.matmul(operator.matrix, self.tensor)
        new_state = QState(tensor=new_tensor)
        new_state.normalize()
        return new_state

class QOperator:
    """Base class for operators that transform a QState."""

    def __init__(self, matrix: torch.Tensor):
        self.matrix = matrix

    @staticmethod
    def create_superposition_op(dim: int) -> 'QOperator':
        """Creates an operator similar to a Hadamard gate to distribute probability."""
        # A simple normalized matrix where all entries are 1/sqrt(dim)
        val = 1.0 / (dim ** 0.5)
        matrix = torch.full((dim, dim), val, dtype=torch.complex64)
        return QOperator(matrix)

    @staticmethod
    def create_priority_op(dim: int, target_idx: int, weight: float = 2.0) -> 'QOperator':
        """Creates an operator that boosts the amplitude of a specific index."""
        matrix = torch.eye(dim, dtype=torch.complex64)
        matrix[target_idx, target_idx] *= weight
        return QOperator(matrix)

